// Handler convention: module src/handlers/<type>.js exports { type, handle }
// where type is kebab-case and equals the filename stem, and
// handle(e) returns `${type}:${e.payload.n}`.
module.exports = { type: "ping", handle: (e) => `ping:${e.payload.n}` };

// Registers every handler and re-exports the registry surface.
const registry = require("./registry.js");
const ping = require("./handlers/ping.js");
registry.register(ping);
module.exports = { register: registry.register, all: registry.all };

const test = require("node:test");
const assert = require("node:assert");
const { all } = require("../src/index.js");

const TYPE_RE = /^[a-z]+(-[a-z]+)*$/;

test("every registered handler honors the convention", () => {
  const handlers = all();
  assert.ok(handlers.length >= 1, "at least one handler must be registered");
  for (const h of handlers) {
    assert.ok(TYPE_RE.test(h.type), `type not kebab-case: ${h.type}`);
    assert.strictEqual(
      h.handle({ payload: { n: 5 } }),
      h.type + ":5",
      `handle output mismatch for ${h.type}`
    );
  }
});
